import React from "react";

function AnimatedBackground() {
  return (
    <div className="fixed inset-0 -z-10 overflow-hidden">

      {/* Glow 1 */}
      <div className="absolute w-[400px] h-[400px] bg-blue-500 rounded-full blur-[120px] opacity-30 animate-pulse top-[-100px] left-[-100px]" />

      {/* Glow 2 */}
      <div className="absolute w-[500px] h-[500px] bg-purple-500 rounded-full blur-[140px] opacity-20 animate-pulse bottom-[-150px] right-[-150px]" />

      {/* Glow 3 */}
      <div className="absolute w-[300px] h-[300px] bg-cyan-400 rounded-full blur-[120px] opacity-20 animate-pulse top-[40%] left-[60%]" />

      {/* Particles */}
      <div className="absolute w-full h-full">
        {[...Array(25)].map((_, i) => (
          <span
            key={i}
            className="absolute w-1 h-1 bg-white/40 rounded-full animate-ping"
            style={{
              top: `${Math.random() * 100}%`,
              left: `${Math.random() * 100}%`,
              animationDuration: `${2 + Math.random() * 3}s`,
            }}
          />
        ))}
      </div>

    </div>
  );
}

export default AnimatedBackground;
